const data = $getWorkflowStaticData('global');
const body = $json.body || $json;
const action = body.action;
const page = body.page || 'unknown';

if (!data.visitors) data.visitors = {};
if (!data.candles) data.candles = {};

if (action === 'visit') {
  data.visitors[page] = (data.visitors[page] || 0) + 1;
  return [{json: {ok: true, visitors: data.visitors[page], candles: data.candles[page] || 0}}];
}

if (action === 'candle') {
  data.candles[page] = (data.candles[page] || 0) + 1;
  return [{json: {ok: true, candles: data.candles[page], visitors: data.visitors[page] || 0}}];
}

if (action === 'stats') {
  return [{json: {
    visitors: data.visitors[page] || 0,
    candles: data.candles[page] || 0
  }}];
}

return [{json: {error: 'unknown action'}}];
